    } else if (msg.includes('liquidity')) {
      errorMessage = 'Not enough liquidity for this swap.'
    } else if (msg.includes('slippage')) {
      errorMessage = 'Slippage tolerance too low. Try increasing it.'
    }
    toast.error(errorMessage)
    setIsSwapping(false)
  }
}

